handle_new_user:
[
  {
    "function_def": "CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_tenant_id   uuid := gen_random_uuid();
  v_nombre      text;
  v_email       text;
BEGIN
  v_email  := NEW.email;
  v_nombre := split_part(v_email, '@', 1);

  INSERT INTO public.tenants (
    tenant_id, nombre, plan, activo, requiere_cita
  ) VALUES (
    v_tenant_id, v_nombre, 'starter', true, false
  );

  INSERT INTO public.socios (
    usuario_id, tenant_id, correo, nombre_completo, estado, tier
  ) VALUES (
    NEW.id,
    v_tenant_id,
    v_email,
    COALESCE(
      NEW.raw_user_meta_data ->> 'full_name',
      NEW.raw_user_meta_data ->> 'name',
      split_part(v_email, '@', 1)
    ),
    'activo',
    'free'
  );

  RETURN NEW;
END;
$function$
"
  }
]

